#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e2+5; 
int n,k,a[MAXN],f[MAXN][MAXN][MAXN];
signed main(void)
{
	cin>>n>>k;
	FOR(i,1,n) cin>>a[i];
	FOR(len,1,n)
	{
		FOR(l,1,n-len+1)
		{
			int r=l+len-1;
			if(l==r)
			{
				f[l][r][0]=a[l];
				continue;
			}
			FOR(mid,l,r-1)
			{
				FOR(c,0,r-l-1)
				{
					FOR(c1,max(0ll,c-r+mid-1),min(mid-l,c))
					{
						if(r-mid-1<c-c1)continue;
						f[l][r][c]=max(f[l][r][c],f[l][mid][c1]+f[mid+1][r][c-c1]);
					}
					FOR(c1,max(0ll,c-r+mid),min(mid-l,c-1))
					{				
						if(r-mid-1<c-c1-1)continue;
						f[l][r][c]=max(f[l][r][c],f[l][mid][c1]*f[mid+1][r][c-1-c1]);
					}
				}	
			}
		}
	}
	cout<<f[1][n][k];
	return false;
}
